// ── CONFIG ─────────────────────────────────────────
// Change LEADS_PER_DAY to scale up later (50, 100, etc)
const LEADS_PER_DAY = 10;
const TARGET_REGIONS = ['United States', 'United Kingdom', 'United Arab Emirates', 'Saudi Arabia', 'Qatar'];
const TARGET_KEYWORDS = [
  'looking for development team',
  'need software developers',
  'hiring dev agency',
  'ai automation',
  'workflow automation',
  'digital transformation',
  'mvp development',
  'outsource development',
  'tech team augmentation'
];
// ────────────────────────────────────────────────────

return [
  {
    json: {
      leadsPerDay: LEADS_PER_DAY,
      targetRegions: TARGET_REGIONS,
      targetKeywords: TARGET_KEYWORDS,
      searchQuery: TARGET_KEYWORDS.slice(0, 3).join(' OR '),
      runDate: new Date().toISOString().split('T')[0]
    }
  }
];

// Handle LinkedIn API response OR Phantombuster/Apify response
// This normalizer works with both sources

const raw = $input.first().json;

// Check for HTTP errors
if (raw.error || raw.statusCode >= 400) {
  throw new Error(`LinkedIn API error: ${JSON.stringify(raw.error || raw.message || raw)}`);
}

// Normalize — handles both LinkedIn API and Phantombuster formats
const elements = raw.elements || raw.leads || raw.profiles || raw.results || [];

if (!elements.length) {
  // Return empty so downstream handles gracefully
  return [{ json: { __empty: true, message: 'No leads returned', runDate: new Date().toISOString() } }];
}

const normalized = elements.map((p, idx) => {
  const firstName = p.firstName || p.first_name || p.name?.split(' ')[0] || 'there';
  const lastName = p.lastName || p.last_name || p.name?.split(' ').slice(1).join(' ') || '';
  const company = p.company || p.currentCompany || p.positions?.[0]?.companyName || '';
  const role = p.title || p.currentTitle || p.positions?.[0]?.title || '';
  const location = p.location || p.geo || '';
  const profileUrl = p.publicProfileUrl || p.linkedinUrl || p.profileUrl || p.url || '';
  const urn = p.entityUrn || p.id || p.profileId || `lead_${Date.now()}_${idx}`;

  // Detect region
  let region = 'unknown';
  const loc = location.toLowerCase();
  if (loc.includes('united states') || loc.includes('usa') || loc.includes(', us')) region = 'US';
  else if (loc.includes('united kingdom') || loc.includes('uk') || loc.includes('england') || loc.includes('london')) region = 'UK';
  else if (loc.includes('dubai') || loc.includes('uae') || loc.includes('emirates') || loc.includes('saudi') || loc.includes('qatar') || loc.includes('riyadh')) region = 'ARAB';

  return {
    json: {
      id: urn,
      firstName,
      lastName,
      fullName: `${firstName} ${lastName}`.trim(),
      company,
      role,
      location,
      region,
      profileUrl,
      email: p.email || p.emailAddress || '',
      about: p.summary || p.about || '',
      connections: p.connectionsCount || 0,
      runDate: new Date().toISOString().split('T')[0]
    }
  };
});

// Filter only target regions
return normalized.filter(item => ['US','UK','ARAB'].includes(item.json.region));

// Deduplicate: skip leads already in GSheet
const newLeads = $('Normalize Lead Data').all();
const existingRows = $('Read Existing Leads').all();

// Build set of known identifiers
const knownIds = new Set();
const knownEmails = new Set();
const knownUrls = new Set();

existingRows.forEach(row => {
  if (row.json.id) knownIds.add(String(row.json.id));
  if (row.json.email) knownEmails.add(row.json.email.toLowerCase().trim());
  if (row.json.profileUrl) knownUrls.add(row.json.profileUrl.toLowerCase().trim());
});

const fresh = newLeads.filter(lead => {
  const id = String(lead.json.id || '');
  const email = (lead.json.email || '').toLowerCase().trim();
  const url = (lead.json.profileUrl || '').toLowerCase().trim();

  // Skip if DO_NOT_CONTACT status found
  const existing = existingRows.find(r => r.json.profileUrl === url || r.json.id === id);
  if (existing && existing.json.status === 'do_not_contact') return false;

  return !knownIds.has(id) && !knownUrls.has(url) && (email === '' || !knownEmails.has(email));
});

console.log(`Dedup: ${newLeads.length} new → ${fresh.length} unique`);
return fresh;

const lead = $('Process One by One').item.json;
const hunterResp = $input.first().json;

// Merge email from Hunter if not already present
let email = lead.email || '';
if (!email && hunterResp?.data?.email) {
  email = hunterResp.data.email;
}

// Skip if still no email
if (!email) {
  return [{ json: { ...lead, email: '', __skipNoEmail: true } }];
}

return [{ json: { ...lead, email } }];

const lead = $('Check Email?').item.json;
const geminiRaw = $input.first()?.json?.text || $input.first()?.json?.content || '';

let emailData = { subject: '', body: '' };

try {
  // Strip markdown code fences if present
  const clean = geminiRaw.replace(/```json\n?|```\n?/g, '').trim();
  emailData = JSON.parse(clean);
} catch (e) {
  // Fallback template if Gemini output is malformed
  emailData = {
    subject: `Quick question about ${lead.company || 'your tech stack'}`,
    body: `Hi ${lead.firstName},\n\nI came across your profile and noticed you're leading tech initiatives at ${lead.company || 'your company'}.\n\nAt Krapton, we help companies like yours build and scale with custom development and AI automation. We've worked with teams across ${lead.region} and would love to explore if we can add value.\n\nWorth a quick chat?\n\nBest,\n[Your Name] | Krapton.com`,
    personalization_note: 'Fallback template used'
  };
}

// Validate subject and body exist
if (!emailData.subject || emailData.subject.length < 3) {
  emailData.subject = `A quick note from Krapton for ${lead.firstName}`;
}
if (!emailData.body || emailData.body.length < 20) {
  throw new Error('Email body too short, skipping lead: ' + lead.fullName);
}

// Add lead data for downstream nodes
return [{
  json: {
    ...lead,
    emailSubject: emailData.subject,
    emailBody: emailData.body,
    personalizationNote: emailData.personalization_note || '',
    generatedAt: new Date().toISOString()
  }
}];

const lead = $('Parse & Validate Email Draft').item.json;
const sendResult = $input.first().json;

// Capture Gmail thread ID for reply tracking
const threadId = sendResult?.id || sendResult?.threadId || '';

const status = sendResult?.error ? 'send_error' : 'sent';
const errorNote = sendResult?.error ? String(sendResult.error).substring(0, 200) : '';

return [{
  json: {
    ...lead,
    status,
    sentDate: new Date().toISOString().split('T')[0],
    threadId,
    errorNote,
    fu1Date: '',
    fu2Date: '',
    replyDate: '',
    category: '',
    notes: lead.personalizationNote || ''
  }
}];

const rows = $input.all();
const today = new Date();
today.setHours(0,0,0,0);

const toFollowUp = [];

rows.forEach(row => {
  const r = row.json;
  if (!r.Email || !r['Sent Date']) return;
  if (r['Do Not Contact'] === 'TRUE') return;
  // Skip if already replied, queried, done, or error
  if (['replied', 'queried', 'done', 'do_not_contact', 'send_error'].includes(r.Status)) return;

  const sentDate = new Date(r['Sent Date']);
  sentDate.setHours(0,0,0,0);
  const daysSinceSent = Math.floor((today - sentDate) / (1000 * 60 * 60 * 24));

  // Follow-up 1: 2 days after initial send, not yet sent
  if (r.Status === 'sent' && daysSinceSent >= 2 && !r['FU1 Date']) {
    toFollowUp.push({ json: { ...r, followUpNumber: 1, daysSinceSent } });
    return;
  }

  // Follow-up 2: 5 days after initial send, FU1 done, not yet sent
  if (r.Status === 'fu1_sent' && daysSinceSent >= 5 && !r['FU2 Date']) {
    toFollowUp.push({ json: { ...r, followUpNumber: 2, daysSinceSent } });
    return;
  }
});

console.log(`Follow-ups due today: ${toFollowUp.length}`);
return toFollowUp.length ? toFollowUp : [{ json: { __noFollowUps: true } }];

const lead = $('Process Follow-ups One by One').item.json;
const geminiRaw = $input.first()?.json?.text || $input.first()?.json?.content || '';

let emailData = { subject: '', body: '' };
try {
  const clean = geminiRaw.replace(/```json\n?|```\n?/g, '').trim();
  emailData = JSON.parse(clean);
} catch(e) {
  const isLast = lead.followUpNumber === 2;
  emailData = {
    subject: `Re: ${lead['Email Subject']}`,
    body: isLast
      ? `Hi ${lead['First Name']}, just dropping one last note. If now isn't the right time, no worries at all — I'll leave it here. Whenever you're exploring tech solutions, Krapton is happy to help. All the best!\n\n[Your Name] | Krapton.com`
      : `Hi ${lead['First Name']}, just following up on my note from a couple of days ago. Did it reach you?\n\nHappy to answer any questions.\n\n[Your Name] | Krapton.com`
  };
}

return [{
  json: {
    ...lead,
    fuSubject: emailData.subject || `Re: ${lead['Email Subject']}`,
    fuBody: emailData.body
  }
}];

const lead = $('Parse Follow-up Draft').item.json;
const sendResult = $input.first().json;
const today = new Date().toISOString().split('T')[0];
const fuNum = lead.followUpNumber;

const updates = {};
if (fuNum === 1) {
  updates['Status'] = 'fu1_sent';
  updates['FU1 Date'] = today;
} else if (fuNum === 2) {
  updates['Status'] = 'fu2_sent';
  updates['FU2 Date'] = today;
}

if (sendResult?.error) {
  updates['Error Note'] = `FU${fuNum} error: ${String(sendResult.error).substring(0,200)}`;
}

return [{ json: { ...lead, updates, rowIdentifier: lead.Email } }];

// Pre-classify obvious spam before hitting Gemini (save API calls)
const email = $input.first().json;
const from = (email.from || '').toLowerCase();
const subject = (email.subject || '').toLowerCase();
const snippet = (email.snippet || email.text || '').toLowerCase();

// Hard spam patterns
const spamPatterns = [
  'unsubscribe', 'opt-out', 'noreply', 'no-reply', 'mailer-daemon',
  'donotreply', 'newsletter', 'promotional', 'notification@', 'alerts@',
  'linkedin.com/comm', 'twitter.com', 'facebook.com', 'instagram.com',
  'automated message', 'do not reply'
];

const isObviousSpam = spamPatterns.some(p => from.includes(p) || subject.includes(p));

return [{
  json: {
    ...email,
    fromEmail: (email.from || '').match(/<(.+?)>/)?.[1] || email.from || '',
    subject: email.subject || '',
    bodyText: email.text || email.snippet || '',
    isObviousSpam,
    receivedAt: new Date().toISOString()
  }
}];

const incomingEmail = $('Skip Obvious Spam?').item.json;
const rows = $('Read Leads for Email Match').all();

// Try to match incoming email to a lead we contacted
const fromEmail = incomingEmail.fromEmail.toLowerCase().trim();
let matchedLead = null;

for (const row of rows) {
  const leadEmail = (row.json.Email || '').toLowerCase().trim();
  if (leadEmail && leadEmail === fromEmail) {
    matchedLead = row.json;
    break;
  }
}

return [{
  json: {
    ...incomingEmail,
    matchedLead: matchedLead || null,
    isFromKnownLead: !!matchedLead
  }
}];

const emailData = $('Match Email to Known Lead').item.json;
const geminiRaw = $input.first()?.json?.text || $input.first()?.json?.content || '';

let classification = { category: 'other', summary: 'Parse error', sentiment: 'unknown', urgency: 'low' };
try {
  const clean = geminiRaw.replace(/```json\n?|```\n?/g, '').trim();
  classification = JSON.parse(clean);
} catch(e) {
  console.log('Classification parse error, defaulting to other');
}

return [{
  json: {
    ...emailData,
    category: classification.category || 'other',
    summary: classification.summary || '',
    sentiment: classification.sentiment || 'unknown',
    urgency: classification.urgency || 'low',
    classifiedAt: new Date().toISOString()
  }
}];

// Spam: just archive it silently, no notification
const email = $input.first().json;
console.log(`Spam archived from: ${email.fromEmail}`);
return [];

const email = $input.first().json;

const urgencyEmoji = { high: '🔴', medium: '🟡', low: '🟢' }[email.urgency] || '⚪';
const sentimentEmoji = { positive: '✅', negative: '❌', neutral: '➡️' }[email.sentiment] || '';

const message = [
  `${urgencyEmoji} RESPONSE RECEIVED — Krapton Outreach`,
  ``,
  `From: ${email.fromEmail}`,
  `Subject: ${email.subject}`,
  `Sentiment: ${sentimentEmoji} ${email.sentiment}`,
  `Urgency: ${email.urgency}`,
  `Summary: ${email.summary}`,
  email.matchedLead ? `Lead: ${email.matchedLead['Full Name']} @ ${email.matchedLead.Company}` : `Lead: Unknown (cold inbound)`,
  ``,
  `Preview: ${(email.bodyText || '').substring(0, 300)}`,
  ``,
  `→ Check GSheet: https://docs.google.com/spreadsheets/d/${process.env.GSHEET_ID}`
].join('\n');

return [{ json: { ...email, notificationMessage: message, notificationType: 'response' } }];

const email = $('Parse Classification').item.json;
const today = new Date().toISOString().split('T')[0];

if (!email.isFromKnownLead || !email.matchedLead?.Email) {
  // Log cold inbound separately
  return [{ json: { ...email, __coldInbound: true } }];
}

const statusMap = {
  response: 'replied',
  query: 'queried',
  other: null
};
const newStatus = statusMap[email.category];

return [{
  json: {
    email: email.matchedLead.Email,
    status: newStatus,
    replyDate: today,
    category: email.category,
    summary: email.summary,
    sentiment: email.sentiment,
    shouldUpdate: !!newStatus
  }
}];

const rows = $input.all();

const stats = {
  total: rows.length,
  sent: 0, fu1: 0, fu2: 0,
  replied: 0, queried: 0,
  errors: 0, done: 0,
  regions: { US: 0, UK: 0, ARAB: 0 }
};

rows.forEach(r => {
  const s = r.json.Status || '';
  if (s === 'sent') stats.sent++;
  if (s === 'fu1_sent') stats.fu1++;
  if (s === 'fu2_sent' || s === 'done') { stats.fu2++; stats.done++; }
  if (s === 'replied') stats.replied++;
  if (s === 'queried') stats.queried++;
  if (s === 'send_error') stats.errors++;
  const region = r.json.Region || 'unknown';
  if (stats.regions[region] !== undefined) stats.regions[region]++;
});

const responseRate = stats.total > 0 ? ((stats.replied + stats.queried) / stats.total * 100).toFixed(1) : 0;

const report = [
  '📊 KRAPTON OUTREACH — WEEKLY REPORT',
  `Week ending: ${new Date().toLocaleDateString()}`,
  '',
  `Total leads in system: ${stats.total}`,
  `In progress (sent): ${stats.sent}`,
  `Follow-up 1 sent: ${stats.fu1}`,
  `Follow-up 2 sent: ${stats.fu2}`,
  `Replied: ${stats.replied}`,
  `Queried (interested): ${stats.queried}`,
  `Errors: ${stats.errors}`,
  '',
  `Response rate: ${responseRate}%`,
  '',
  `By region — US: ${stats.regions.US} | UK: ${stats.regions.UK} | Arab: ${stats.regions.ARAB}`,
  '',
  `→ Full data: https://docs.google.com/spreadsheets/d/${$env.GSHEET_ID}`
].join('\n');

return [{ json: { report } }];
